async (page) => {
  // Walk to Forester at (216, 114)
  await page.evaluate(() => window.__clickTile(216, 114));
  await page.waitForTimeout(5000);

  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  const forester = await page.evaluate(() => window.__latestGameState?.nearby_entities?.find(e=>e.name==='Forester'));

  return JSON.stringify({ pos, forester: forester ? {id: forester.id, dist: forester.distance, on_screen: forester.on_screen, quest: forester.quest_npc} : null });
}

async (page) => {
  // Get adjacent to Forester at (216,114) - go to (217,114)
  await page.evaluate(() => window.__clickTile(217, 114));
  await page.waitForTimeout(2000);

  const forester = await page.evaluate(() => window.__latestGameState?.nearby_entities?.find(e=>e.name==='Forester'));
  const foresterId = forester?.id;

  // Talk 8 times
  let stageChanged = false;
  for (let i = 0; i < 8; i++) {
    await page.evaluate((id) => window.__talkToNPC(id), foresterId);
    await page.waitForTimeout(1500);

    const stage = await page.evaluate(() => window.__latestGameState?.quests?.find(q=>q.key==='foresting')?.stage);
    const logs = await page.evaluate(() => window.__latestGameState?.inventory?.filter(i=>i.key==='logs').length || 0);
    if (stage > 2 || logs < 10) { stageChanged = true; break; }
  }

  const quest = await page.evaluate(() => window.__latestGameState?.quests?.find(q=>q.key==='foresting'));
  const inv = await page.evaluate(() => window.__latestGameState?.inventory?.map(i=>({key:i.key,name:i.name,slot:i.slot})));
  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  const dist = await page.evaluate(() => window.__latestGameState?.nearby_entities?.find(e=>e.name==='Forester')?.distance);

  return JSON.stringify({ pos, dist, stageChanged, quest, inventory: inv });
}
